import asyncio
import websockets
import json
import uuid
import time
import math

# --- Configuration ---
PORT = 8080
GAME_TICK_RATE = 30  # Server updates and broadcasts 30 times per second
PLAYER_MOVE_SPEED = 0.1 # Units per game tick
PLAYER_ROT_SPEED = 0.05 # Radians per game tick for yaw rotation

# --- Game State ---
# Structure for each player in game_state:
# {
#   "id": "player_uuid",
#   "x": 0.0,
#   "y": 0.0, # Ground level, assuming y-up coordinate system
#   "z": 0.0,
#   "rot_y": 0.0, # Rotation around Y-axis (yaw), in radians
#   "health": 100,
#   "input_state": {
#     "move_forward": 0, # -1 for backward, 1 for forward
#     "move_right": 0,   # -1 for left, 1 for right (strafe)
#     "rotate_yaw": 0    # -1 for left, 1 for right (turn)
#   }
# }
game_state = {}

# Set of currently connected WebSocket client connections
connected_clients = set()

# --- Player Management ---
async def register_player(websocket):
    """Registers a new player upon connection, assigns an ID, and adds to game_state."""
    player_id = str(uuid.uuid4())
    game_state[player_id] = {
        "id": player_id,
        "x": 0.0,
        "y": 1.0, # Start player slightly above ground
        "z": 0.0,
        "rot_y": 0.0,
        "health": 100,
        "input_state": { # This is server-internal and not broadcast
            "move_forward": 0,
            "move_right": 0,
            "rotate_yaw": 0
        }
    }
    connected_clients.add(websocket)
    print(f"Player {player_id} connected. Total players: {len(game_state)}")
    
    # Send initial state to the newly connected player, including their own ID
    # The client can use this player_id to identify its own state in broadcasts
    await websocket.send(json.dumps({"type": "init", "player_id": player_id}))
    return player_id

async def unregister_player(websocket, player_id):
    """Removes a player from game_state and connected_clients upon disconnection."""
    connected_clients.discard(websocket)
    if player_id in game_state:
        del game_state[player_id]
    print(f"Player {player_id} disconnected. Total players: {len(game_state)}")

# --- Game Logic ---
def update_player_input(player_id, message):
    """Processes input messages from clients and updates their input_state."""
    if player_id in game_state and "input" in message:
        input_data = message["input"]
        player = game_state[player_id]
        
        # Update input state, clamping values to -1, 0, or 1
        player["input_state"]["move_forward"] = max(-1, min(1, int(input_data.get("move_forward", 0))))
        player["input_state"]["move_right"] = max(-1, min(1, int(input_data.get("move_right", 0))))
        player["input_state"]["rotate_yaw"] = max(-1, min(1, int(input_data.get("rotate_yaw", 0))))

def apply_game_tick():
    """Applies all game logic for one tick, updating player positions, rotations, etc."""
    for player_id, player in game_state.items():
        input_state = player["input_state"]

        # Apply rotation
        player["rot_y"] += input_state["rotate_yaw"] * PLAYER_ROT_SPEED
        # Normalize rotation to stay within -PI to PI or 0 to 2PI if desired
        player["rot_y"] %= (2 * math.pi) 

        # Calculate movement based on current rotation (forward/backward and strafe)
        move_vec_x = 0
        move_vec_z = 0

        # Forward/Backward movement
        if input_state["move_forward"] != 0:
            move_vec_x += math.sin(player["rot_y"]) * input_state["move_forward"]
            move_vec_z += math.cos(player["rot_y"]) * input_state["move_forward"]

        # Strafe (left/right) movement
        if input_state["move_right"] != 0:
            # Strafing is perpendicular to the forward direction
            move_vec_x += math.cos(player["rot_y"]) * input_state["move_right"]
            move_vec_z -= math.sin(player["rot_y"]) * input_state["move_right"]

        # Normalize combined movement vector to prevent faster diagonal movement
        move_length = math.sqrt(move_vec_x**2 + move_vec_z**2)
        if move_length > 0:
            player["x"] += (move_vec_x / move_length) * PLAYER_MOVE_SPEED
            player["z"] += (move_vec_z / move_length) * PLAYER_MOVE_SPEED

        # Example: Simple boundary (uncomment to enable)
        # player["x"] = max(-50, min(50, player["x"]))
        # player["z"] = max(-50, min(50, player["z"]))

async def game_loop():
    """The main game loop, responsible for updating state and broadcasting it."""
    while True:
        tick_start_time = time.time()

        # 1. Apply all game logic updates for this tick
        apply_game_tick()

        # 2. Prepare and broadcast the current game state to all clients
        if connected_clients:
            # Create a broadcast-friendly version of the game state.
            # We exclude 'input_state' as it's internal server logic.
            broadcast_state = {
                pid: {k: v for k, v in p.items() if k != "input_state"}
                for pid, p in game_state.items()
            }
            message = json.dumps({"type": "game_state", "state": broadcast_state})

            # Send the message to all connected clients concurrently.
            # `return_exceptions=True` prevents a single client error from stopping other broadcasts.
            await asyncio.gather(*[
                client.send(message) for client in connected_clients
            ], return_exceptions=True)

        # 3. Control the game tick rate
        elapsed_time = time.time() - tick_start_time
        sleep_time = (1 / GAME_TICK_RATE) - elapsed_time
        if sleep_time > 0:
            await asyncio.sleep(sleep_time)
        else:
            # Warn if the game tick takes longer than the desired interval
            print(f"Warning: Game tick took too long: {elapsed_time:.4f}s")


# --- WebSocket Handler ---
async def handler(websocket, path):
    """Handles individual client connections and their incoming messages."""
    player_id = await register_player(websocket)
    try:
        # Loop to continuously receive messages from this client
        async for message_str in websocket:
            message = json.loads(message_str)
            if message.get("type") == "input":
                update_player_input(player_id, message)
            # Future: Handle other message types (e.g., "fire", "interact", "chat")
            else:
                print(f"Received unknown message type from {player_id}: {message}")
    except websockets.exceptions.ConnectionClosedOK:
        print(f"Connection with {player_id} closed gracefully.")
    except websockets.exceptions.ConnectionClosedError as e:
        print(f"Connection with {player_id} closed with error: {e}")
    except Exception as e:
        # Catch any other unexpected errors during message handling
        print(f"An unexpected error occurred with {player_id}: {e}")
    finally:
        # Ensure player is unregistered regardless of how the connection closed
        await unregister_player(websocket, player_id)

# --- Main Server Setup ---
async def main():
    print(f"Starting Battle Royale server on ws://localhost:{PORT}")
    
    # Start the WebSocket server
    server = await websockets.serve(handler, "0.0.0.0", PORT)

    # Start the game loop as a background task, running concurrently with the server
    asyncio.create_task(game_loop())

    # Keep the main thread alive, waiting for the server to explicitly close
    await server.wait_closed()

if __name__ == "__main__":
    try:
        asyncio.run(main())
    except KeyboardInterrupt:
        print("Server stopped by user (KeyboardInterrupt).")
    except Exception as e:
        print(f"An unhandled error occurred in main: {e}")